  1	import * as React from 'react';
  2	import { Button } from '@patternfly/react-core';
  3	import { PlusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/plus-circle-icon';
  4	import { Formik, useField, useFormikContext } from 'formik';
  5	import { useTranslation } from 'react-i18next';
  6	import { SecretAnnotationId } from '../../consts';
  7	import { SecretModel } from '../../models';
  8	import {
  9	  associateServiceAccountToSecret,
 10	  getSecretAnnotations,
 11	} from '../utils/pipeline-utils';
 12	import { k8sCreate } from '@openshift-console/dynamic-plugin-sdk';
 13	import { CommonPipelineModalFormikValues, SecretType } from '../../types';
 14	import { ExpandCollapse } from './expand-collapse';
 15	import { advancedSectionValidationSchema } from '../start-pipeline/validation-utils';
 16	import SecretForm from './SecretForm';
 17	import SecretsList from './SecretsList';
 18	import './PipelineSecretSection.scss';
 19	
 20	const initialValues = {
 21	  secretName: '',
 22	  annotations: { key: SecretAnnotationId.Image, value: '' },
 23	  type: SecretType.dockerconfigjson,
 24	  formData: {},
 25	};
 26	
 27	const PipelineSecretSection: React.FC = () => {
 28	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 29	  const [secretOpenField] = useField<boolean>('secretOpen');
 30	  const {
 31	    setFieldValue,
 32	    values: { namespace },
 33	  } = useFormikContext<CommonPipelineModalFormikValues>();
 34	
 35	  const handleSubmit = (values, actions) => {
 36	    const newSecret = {
 37	      apiVersion: SecretModel.apiVersion,
 38	      kind: SecretModel.kind,
 39	      metadata: {
 40	        name: values.secretName,
 41	        namespace,
 42	        annotations: getSecretAnnotations(values.annotations),
 43	      },
 44	      type: values.type,
 45	      stringData: values.formData,
 46	    };
 47	    return k8sCreate({ model: SecretModel, data: newSecret })
 48	      .then((resp) => {
 49	        setFieldValue(secretOpenField.name, false);
 50	        associateServiceAccountToSecret(
 51	          resp,
 52	          namespace,
 53	          values.annotations.key === SecretAnnotationId.Image,
 54	        );
 55	      })
 56	      .catch((err) => {
 57	        actions.setStatus({ submitError: err.message });
 58	      });
 59	  };
 60	
 61	  const handleReset = (values, actions) => {
 62	    actions.resetForm({ values: initialValues, status: {} });
 63	    setFieldValue(secretOpenField.name, false);
 64	  };
 65	
 66	  return (
 67	    <ExpandCollapse
 68	      textExpanded={t('Hide credential options')}
 69	      textCollapsed={t('Show credential options')}
 70	    >
 71	      <div className="odc-pipeline-secret-section">
 72	        <p>
 73	          {t(
 74	            'The following secrets are available for all pipelines in this namespace to authenticate to the specified Git server or Image registry:',
 75	          )}
 76	        </p>
 77	        <div className="odc-pipeline-secret-section__secrets">
 78	          <SecretsList namespace={namespace} />
 79	          {secretOpenField.value ? (
 80	            <div className="odc-pipeline-secret-section__secret-form">
 81	              <Formik
 82	                initialValues={initialValues}
 83	                validationSchema={advancedSectionValidationSchema()}
 84	                onSubmit={handleSubmit}
 85	                onReset={handleReset}
 86	              >
 87	                {(formikProps) => <SecretForm {...formikProps} />}
 88	              </Formik>
 89	            </div>
 90	          ) : (
 91	            <Button
 92	              variant="link"
 93	              onClick={() => {
 94	                setFieldValue(secretOpenField.name, true);
 95	              }}
 96	              className="odc-pipeline-secret-section__secret-action"
 97	              icon={<PlusCircleIcon />}
 98	            >
 99	              {t('Add Secret')}
100	            </Button>
101	          )}
102	        </div>
103	      </div>
104	    </ExpandCollapse>
105	  );
106	};
107	
108	export default PipelineSecretSection;

